function Load_Grfc(tipo,base,div){
    const mapa = {Barra:'bar',Linha:'line',Pizza:'pie',Rosca:'doughnut',Radar:'radar',Polar:'polarArea'}
    div.chartInstance?.destroy() // limpa gráfico anterior
    div.chartInstance = new Chart(div,{
        type: mapa[tipo], data: base,
        options:{responsive: true,animation: {duration: 1000,easing: 'easeOutBounce'},
            plugins: {
            legend: { labels: { color: '#fff' } },
            title:  { display: true, text: `Gráfico de ${tipo}`, color: '#ff79c6' }},
            scales: {
            x: { ticks: { color: '#c084fc' }, grid: { color: '#2a2a40' } },
            y: { ticks: { color: '#f97316' }, grid: { color: '#2a2a40' } }}}
    })
}
function Charte(labels,data,labelGrafico,cor='#c084fc'){ 
    return {labels,datasets: [{
            label: labelGrafico,
            data,
            backgroundColor: isArr(cor) ? cor : [cor],
            borderColor: '#fff',
            borderWidth: 1,
            tension: 0.4
        }]
    }
}

const CharteGrup = (obj,labelGrafico,cores)=>{
    const labels = ObjKey(obj)
    const grupos = [...new Set(ObjVal(obj).flatMap(e=>ObjKey(e)))]
    return {
        labels,
        datasets: grupos.map((g,i)=>({
            label: `${labelGrafico} — ${g}`,
            data: labels.map(l=>obj[l]?.[g] || 0),
            backgroundColor: cores[i % cores.length],
            borderColor: '#fff',
            borderWidth: 1
        }))
    }
}

function BtnOff(btn,stg,Tru){AddTrue(btn,'BrnOff',Tru) ; btn.textContent=stg}

function CopyTagImg(btn,div,scale=1) { // btn=Botão q clikei , e=Div  s= Escala 1 ou eu escolho
  if (!btn || !div) return ; if (!document.hasFocus()) return
  BtnOff(btn,'Copiando...',true)
  html2canvas(div, {scale,backgroundColor: null,useCORS: true})
  .then(c => new Promise(r => c.toBlob(r)))
  .then(b => navigator.clipboard.write([new ClipboardItem({'image/png':b})]))
  .then(()=> {BtnOff(btn,'Copiado!',false)})
  .catch(()=>{BtnOff(btn,'Erro',false)})
}

const SavePDF2 = async (Div, Nome = "download.pdf") => {
    const { jsPDF } = window.jspdf
    const pdf = new jsPDF("p", "pt", "a4")
    await pdf.html(Div,{x: 20,y: 20,autoPaging: "text",callback: (doc) => doc.save(Nome)});
}

const GetPC = () => {
    const L = ['Balcão','Allan','Render','Baby','Outro']
    let PC = localStorage.PC_NAME

    if (!L.includes(PC)) {
        PC = prompt('Nome do PC:\n\n'+L.join('\n'))
        if (!L.includes(PC)) throw 'PC inválido'
        localStorage.PC_NAME = PC
    }
    const ua = navigator.userAgent
    return {PC,Navgd:ua.includes('Edg')    ? 'Edge'   : ua.includes('Chrome') ? 'Chrome' : ua.includes('Firefox')? 'Firefox': ua.includes('Safari') ? 'Safari' : 'Outro'}
}

function RANGE_DATA(arr,LMT,Atv){ // Array de objetos | Limite ["2026-03-05","2026-12-30"] | Atv=Boolean (se permite isso ou não)
    const has=LMT&&Atv
    let idx0=0,idx1=arr.length-1
    if(has){for(let i=0;i<arr.length   ;i++){const d=arr[i].Data;if(d&&d>=LMT[0]){idx0=i;break}}
            for(let i=arr.length-1;i>=0;i--){const d=arr[i].Data;if(d&&d<=LMT[1]){idx1=i;break}}}
    const out=[]
    for(let i=idx0;i<=idx1;i++){const e=arr[i],d=e.Data ; if(!e.Lixo&&(d==""||!has||d>=LMT[0]&&d<=LMT[1])) out.push(e)}
    return out
}